mapper.select:
SELECT p.id, p.publication_no AS publicationNo, p.title, p.applicant, p.`abstract` AS patentAbstract, p.publication_date AS publicationDate, p.source_type AS sourceType, p.parse_status AS parseStatus, p.created_at AS createdAt, f.remark AS favoriteRemark, f.group_name AS favoriteGroup, f.created_at AS favoriteTime FROM patent_favorite f INNER JOIN patent p ON f.patent_id = p.id
f.user_id = #{userId}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.publication_no LIKE CONCAT('%', #{keyword}, '%') OR p.applicant LIKE CONCAT('%', #{keyword}, '%'))
AND f.group_name = #{groupName}
ORDER BY f.created_at DESC
